# Pages Router

The Pages Router uses the `pages/` directory for file-based routing. Each `.tsx` file becomes a route, and data fetching happens through exported functions.

## Directory Structure

```
pages/
├── _app.tsx           # Custom App — wraps all pages
├── _document.tsx      # Custom Document — controls <html> and <body>
├── index.tsx          # / (home page)
├── about.tsx          # /about
├── blog/
│   ├── index.tsx      # /blog
│   └── [slug].tsx     # /blog/:slug
└── api/
    └── hello.ts       # /api/hello (see [[nextjs/api-routes]])
```

## Basic Page

```tsx
// pages/about.tsx → /about
export default function AboutPage() {
  return <h1>About Us</h1>
}
```

## Static Generation (getStaticProps)

```tsx
// pages/blog.tsx
import type { InferGetStaticPropsType, GetStaticProps } from 'next'

type Post = { id: string; title: string; content: string }

export const getStaticProps: GetStaticProps<{ posts: Post[] }> = async () => {
  const res = await fetch('https://api.example.com/posts')
  const posts: Post[] = await res.json()

  return {
    props: { posts },
    revalidate: 60, // ISR: regenerate every 60 seconds
  }
}

export default function BlogPage({
  posts,
}: InferGetStaticPropsType<typeof getStaticProps>) {
  return (
    <ul>
      {posts.map(post => (
        <li key={post.id}>{post.title}</li>
      ))}
    </ul>
  )
}
```

## Dynamic Routes with getStaticPaths

```tsx
// pages/blog/[slug].tsx
import type { GetStaticPaths, GetStaticProps } from 'next'

export const getStaticPaths: GetStaticPaths = async () => {
  const res = await fetch('https://api.example.com/posts')
  const posts = await res.json()

  const paths = posts.map((post: { slug: string }) => ({
    params: { slug: post.slug },
  }))

  return {
    paths,
    fallback: false, // 404 for unknown slugs
    // fallback: true — show loading then render
    // fallback: 'blocking' — SSR on first request, then cache
  }
}

export const getStaticProps: GetStaticProps = async ({ params }) => {
  const res = await fetch(`https://api.example.com/posts/${params?.slug}`)
  const post = await res.json()

  return { props: { post }, revalidate: 60 }
}

export default function PostPage({ post }: { post: { title: string; content: string } }) {
  return (
    <article>
      <h1>{post.title}</h1>
      <div dangerouslySetInnerHTML={{ __html: post.content }} />
    </article>
  )
}
```

## Server-Side Rendering (getServerSideProps)

```tsx
// pages/dashboard.tsx
import type { GetServerSideProps } from 'next'

export const getServerSideProps: GetServerSideProps = async (context) => {
  const { req, res, params, query } = context
  const token = req.cookies.session

  if (!token) {
    return { redirect: { destination: '/login', permanent: false } }
  }

  const data = await fetchDashboard(token)
  return { props: { data } }
}

export default function DashboardPage({ data }: { data: DashboardData }) {
  return <Dashboard data={data} />
}
```

## Custom App (_app.tsx)

```tsx
// pages/_app.tsx
import type { AppProps } from 'next/app'
import '@/styles/globals.css'

export default function App({ Component, pageProps }: AppProps) {
  return (
    <Layout>
      <Component {...pageProps} />
    </Layout>
  )
}
```

## Custom Document (_document.tsx)

```tsx
// pages/_document.tsx
import { Html, Head, Main, NextScript } from 'next/document'

export default function Document() {
  return (
    <Html lang="en">
      <Head>
        <link rel="icon" href="/favicon.ico" />
      </Head>
      <body>
        <Main />
        <NextScript />
      </body>
    </Html>
  )
}
```

## Per-Page Layouts

```tsx
// pages/dashboard.tsx
import type { ReactElement } from 'react'
import DashboardLayout from '@/components/DashboardLayout'

export default function DashboardPage() {
  return <h1>Dashboard</h1>
}

DashboardPage.getLayout = function getLayout(page: ReactElement) {
  return <DashboardLayout>{page}</DashboardLayout>
}
```

```tsx
// pages/_app.tsx
import type { ReactElement, ReactNode } from 'react'
import type { NextPage } from 'next'
import type { AppProps } from 'next/app'

type NextPageWithLayout = NextPage & {
  getLayout?: (page: ReactElement) => ReactNode
}

type AppPropsWithLayout = AppProps & {
  Component: NextPageWithLayout
}

export default function App({ Component, pageProps }: AppPropsWithLayout) {
  const getLayout = Component.getLayout ?? ((page) => page)
  return getLayout(<Component {...pageProps} />)
}
```

## Client-Side Data Fetching

```tsx
import useSWR from 'swr'

const fetcher = (url: string) => fetch(url).then(r => r.json())

export default function Profile() {
  const { data, error, isLoading } = useSWR('/api/user', fetcher)

  if (isLoading) return <div>Loading...</div>
  if (error) return <div>Error loading profile</div>
  return <div>Hello {data.name}</div>
}
```
